213	pub fn shellEscape(globalThis: *jsc.JSGlobalObject, callframe: *jsc.CallFrame) bun.JSError!jsc.JSValue {
214	    const arguments = callframe.arguments_old(1);
215	    if (arguments.len < 1) {
216	        return globalThis.throw("shell escape expected at least 1 argument", .{});
217	    }
218	
219	    const jsval = arguments.ptr[0];
220	    const bunstr = try jsval.toBunString(globalThis);
221	    if (globalThis.hasException()) return .zero;
222	    defer bunstr.deref();
223	
224	    var outbuf = std.array_list.Managed(u8).init(bun.default_allocator);
225	    defer outbuf.deinit();
226	
227	    if (bun.shell.needsEscapeBunstr(bunstr)) {
228	        const result = try bun.shell.escapeBunStr(bunstr, &outbuf, true);
229	        if (!result) {
230	            return globalThis.throw("String has invalid utf-16: {s}", .{bunstr.byteSlice()});
231	        }
232	        var str = bun.String.cloneUTF8(outbuf.items[0..]);
233	        return str.transferToJS(globalThis);
234	    }
235	
236	    return jsval;
237	}
