      const ini = Buffer.concat([Buffer.from("key = "), Buffer.from([0xe0])]).toString("latin1");
      expect(() => parse(ini)).not.toThrow();
    });

    test("truncated 3-byte sequence with 1 continuation byte at end", () => {
