describe("Bun.INI", () => {
  test("namespace exists with parse and stringify", () => {
    expect(typeof Bun.INI).toBe("object");
    expect(typeof Bun.INI.parse).toBe("function");
    expect(typeof Bun.INI.stringify).toBe("function");
  });

  describe("parse", () => {
    test("basic key=value pairs", () => {
      const result = Bun.INI.parse("key=value\nfoo=bar");
      expect(result).toEqual({ key: "value", foo: "bar" });
    });

    test("whitespace around = sign", () => {
      const result = Bun.INI.parse("key = value\nfoo =bar\nbaz= qux");
      expect(result).toEqual({ key: "value", foo: "bar", baz: "qux" });
    });

    test("sections as nested objects", () => {
      const result = Bun.INI.parse("[section]\nkey=value");
      expect(result).toEqual({ section: { key: "value" } });
    });

    test("multiple sections", () => {
      const result = Bun.INI.parse("root=1\n[a]\nfoo=bar\n[b]\nbaz=qux");
      expect(result).toEqual({
        root: 1,
        a: { foo: "bar" },
        b: { baz: "qux" },
      });
    });

    test("dotted section names create nested objects", () => {
      const result = Bun.INI.parse("[a.b.c]\nkey=value");
      expect(result).toEqual({ a: { b: { c: { key: "value" } } } });
    });

    test("comment lines with ;", () => {
      const result = Bun.INI.parse("; comment\nkey=value");
      expect(result).toEqual({ key: "value" });
    });

    test("comment lines with #", () => {
      const result = Bun.INI.parse("# comment\nkey=value");
      expect(result).toEqual({ key: "value" });
    });

    test("inline comments", () => {
      const result = Bun.INI.parse("key=value ; comment\nfoo=bar # comment");
      expect(result).toEqual({ key: "value", foo: "bar" });
    });

    test("boolean coercion", () => {
      const result = Bun.INI.parse("a=true\nb=false");
      expect(result).toEqual({ a: true, b: false });
    });

    test("null coercion", () => {
      const result = Bun.INI.parse("a=null");
      expect(result).toEqual({ a: null });
    });

    test("numeric coercion", () => {
      const result = Bun.INI.parse("a=42\nb=3.14\nc=-7\nd=0");
      expect(result).toEqual({ a: 42, b: 3.14, c: -7, d: 0 });
    });

    test("quoted values have quotes stripped", () => {
      const result = Bun.INI.parse('a="hello"\nb=\'world\'');
      expect(result).toEqual({ a: "hello", b: "world" });
    });

    test("quoted values preserve inner spaces", () => {
      const result = Bun.INI.parse('a="hello world"');
      expect(result).toEqual({ a: "hello world" });
    });

    test("keys without = get value true", () => {
      const result = Bun.INI.parse("standalone_key");
      expect(result).toEqual({ standalone_key: true });
    });

    test("empty value after =", () => {
      const result = Bun.INI.parse("key=");
      expect(result).toEqual({ key: "" });
    });

    test("empty input returns empty object", () => {
      const result = Bun.INI.parse("");
      expect(result).toEqual({});
    });

    test("only comments returns empty object", () => {
      const result = Bun.INI.parse("; comment\n# another");
      expect(result).toEqual({});
    });

    test("blank lines are skipped", () => {
      const result = Bun.INI.parse("\n\nkey=value\n\n");
      expect(result).toEqual({ key: "value" });
    });

    test("windows line endings (CRLF)", () => {
      const result = Bun.INI.parse("[section]\r\nkey=value\r\n");
      expect(result).toEqual({ section: { key: "value" } });
    });

    test("section with whitespace around name", () => {
      const result = Bun.INI.parse("[ section ]\nkey=value");
      expect(result).toEqual({ section: { key: "value" } });
    });

    test("root level values before any section", () => {
      const result = Bun.INI.parse("global=yes\n[section]\nlocal=no");
      expect(result).toEqual({ global: "yes", section: { local: "no" } });
    });

    test("throws on undefined/null input", () => {
      expect(() => Bun.INI.parse(undefined as any)).toThrow();
      expect(() => Bun.INI.parse(null as any)).toThrow();
    });

    test("complex example", () => {
      const input = `
; Database configuration
[database]
host = localhost
port = 5432
name = mydb
enabled = true

# Application settings
[app]
debug = false
version = 1.0
title = My Application
`;
      const result = Bun.INI.parse(input);
      expect(result).toEqual({
        database: {
          host: "localhost",
          port: 5432,
          name: "mydb",
          enabled: true,
        },
        app: {
          debug: false,
          version: 1.0,
          title: "My Application",
        },
      });
    });
  });

  describe("stringify", () => {
    test("basic object", () => {
      const result = Bun.INI.stringify({ key: "value", foo: "bar" });
      expect(result).toContain("key=value\n");
      expect(result).toContain("foo=bar\n");
    });

    test("boolean values", () => {
      const result = Bun.INI.stringify({ a: true, b: false });
      expect(result).toContain("a=true\n");
      expect(result).toContain("b=false\n");
    });

    test("null values", () => {
      const result = Bun.INI.stringify({ a: null });
      expect(result).toContain("a=null\n");
    });

    test("number values", () => {
      const result = Bun.INI.stringify({ a: 42, b: 3.14 });
      expect(result).toContain("a=42\n");
      expect(result).toContain("b=3.14\n");
    });

    test("nested objects become sections", () => {
      const result = Bun.INI.stringify({
        section: { key: "value" },
      });
      expect(result).toContain("[section]\n");
      expect(result).toContain("key=value\n");
    });

    test("deeply nested objects use dotted section names", () => {
      const result = Bun.INI.stringify({
        parent: { child: { key: "value" } },
      });
      expect(result).toContain("[parent.child]\n");
      expect(result).toContain("key=value\n");
    });

    test("root primitives before sections", () => {
      const result = Bun.INI.stringify({
        root: "yes",
        section: { key: "value" },
      });
      const rootIdx = result.indexOf("root=yes");
      const sectionIdx = result.indexOf("[section]");
      expect(rootIdx).toBeLessThan(sectionIdx);
    });

    test("skips undefined and function values", () => {
      const result = Bun.INI.stringify({
        a: "keep",
        b: undefined,
        c: () => {},
      });
      expect(result).toContain("a=keep");
      expect(result).not.toContain("b=");
      expect(result).not.toContain("c=");
    });

    test("throws on non-object input", () => {
      expect(() => Bun.INI.stringify("string" as any)).toThrow();
      expect(() => Bun.INI.stringify(null as any)).toThrow();
      expect(() => Bun.INI.stringify(undefined as any)).toThrow();
    });

    test("roundtrip: parse(stringify(obj)) preserves structure", () => {
      const original = {
        name: "test",
        version: 1,
        enabled: true,
        database: {
          host: "localhost",
          port: 5432,
        },
      };
      const roundtripped = Bun.INI.parse(Bun.INI.stringify(original));
      expect(roundtripped).toEqual(original);
    });

    test("empty object produces empty string", () => {
      const result = Bun.INI.stringify({});
      expect(result).toBe("");
    });
  });
});

