      const result = Bun.INI.parse(input);
      expect(result).toEqual({
        database: {
          host: "localhost",
          port: 5432,
          name: "mydb",
          enabled: true,
        },
        app: {
          debug: false,
          version: 1.0,
          title: "My Application",
        },
      });
    });
  });

  describe("stringify", () => {
    test("basic object", () => {
      const result = Bun.INI.stringify({ key: "value", foo: "bar" });
      expect(result).toContain("key=value\n");
      expect(result).toContain("foo=bar\n");
    });

    test("boolean values", () => {
      const result = Bun.INI.stringify({ a: true, b: false });
      expect(result).toContain("a=true\n");
      expect(result).toContain("b=false\n");
    });

    test("null values", () => {
      const result = Bun.INI.stringify({ a: null });
      expect(result).toContain("a=null\n");
    });

    test("number values", () => {
      const result = Bun.INI.stringify({ a: 42, b: 3.14 });
      expect(result).toContain("a=42\n");
      expect(result).toContain("b=3.14\n");
    });

    test("nested objects become sections", () => {
      const result = Bun.INI.stringify({
        section: { key: "value" },
      });
      expect(result).toContain("[section]\n");
      expect(result).toContain("key=value\n");
    });

    test("deeply nested objects use dotted section names", () => {
      const result = Bun.INI.stringify({
        parent: { child: { key: "value" } },
      });
      expect(result).toContain("[parent.child]\n");
      expect(result).toContain("key=value\n");
    });

    test("root primitives before sections", () => {
      const result = Bun.INI.stringify({
        root: "yes",
        section: { key: "value" },
      });
      const rootIdx = result.indexOf("root=yes");
      const sectionIdx = result.indexOf("[section]");
      expect(rootIdx).toBeLessThan(sectionIdx);
    });

    test("skips undefined and function values", () => {
      const result = Bun.INI.stringify({
        a: "keep",
        b: undefined,
        c: () => {},
      });
      expect(result).toContain("a=keep");
      expect(result).not.toContain("b=");
      expect(result).not.toContain("c=");
    });

    test("throws on non-object input", () => {
      expect(() => Bun.INI.stringify("string" as any)).toThrow();
      expect(() => Bun.INI.stringify(null as any)).toThrow();
      expect(() => Bun.INI.stringify(undefined as any)).toThrow();
    });

    test("roundtrip: parse(stringify(obj)) preserves structure", () => {
      const original = {
        name: "test",
        version: 1,
        enabled: true,
        database: {
          host: "localhost",
          port: 5432,
        },
      };
      const roundtripped = Bun.INI.parse(Bun.INI.stringify(original));
      expect(roundtripped).toEqual(original);
    });

    test("empty object produces empty string", () => {
      const result = Bun.INI.stringify({});
      expect(result).toBe("");
    });
  });
});

