1	pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
2	    const object = JSValue.createEmptyObject(globalThis, 2);
3	    object.put(
4	        globalThis,
5	        ZigString.static("parse"),
6	        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
7	    );
8	    object.put(
9	        globalThis,
10	        ZigString.static("stringify"),
11	        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
12	    );
13	    return object;
14	}
15	
16	pub fn parse(
17	    global: *jsc.JSGlobalObject,
18	    callFrame: *jsc.CallFrame,
19	) bun.JSError!jsc.JSValue {
20	    const input_value = callFrame.argument(0);
21	
22	    if (input_value.isEmptyOrUndefinedOrNull()) {
23	        return global.throwInvalidArguments("Expected a string to parse", .{});
24	    }
25	
26	    var input_slice = try input_value.toSlice(global, bun.default_allocator);
27	    defer input_slice.deinit();
28	    const src = input_slice.slice();
29	
30	    const root = JSValue.createEmptyObject(global, 0);
31	    var current_section = root;
32	
33	    var iter = std.mem.splitScalar(u8, src, '\n');
34	    while (iter.next()) |raw_line| {
35	        // Strip trailing \r for Windows line endings
36	        const line = trimLine(raw_line);
37	        const trimmed = std.mem.trim(u8, line, " \t");
38	
39	        if (trimmed.len == 0) continue;
40	        // Comment lines
41	        if (trimmed[0] == ';' or trimmed[0] == '#') continue;
42	
43	        // Section header: [section] or [section.subsection]
44	        if (trimmed[0] == '[') {
45	            const close = std.mem.indexOfScalar(u8, trimmed, ']') orelse continue;
46	            // Verify rest of line after ] is whitespace or comment
47	            if (close + 1 < trimmed.len) {
48	                var rest_is_ok = true;
49	                for (trimmed[close + 1 ..]) |c| {
50	                    switch (c) {
51	                        ' ', '\t' => {},
52	                        ';', '#' => break,
53	                        else => {
54	                            rest_is_ok = false;
55	                            break;
56	                        },
57	                    }
58	                }
59	                if (!rest_is_ok) {
60	                    // Treat as key=value if bracket line is malformed
61	                    try parseKeyValue(global, current_section, trimmed);
62	                    continue;
63	                }
64	            }
65	            const section_name = std.mem.trim(u8, trimmed[1..close], " \t");
66	            if (section_name.len == 0) continue;
67	
68	            // Handle dotted section names: [a.b.c] → root.a.b.c
69	            current_section = try getOrCreateSection(global, root, section_name);
70	            continue;
71	        }
72	
73	        // Key = value (or just key)
74	        try parseKeyValue(global, current_section, trimmed);
75	    }
76	
77	    return root;
78	}
79	
80	fn getOrCreateSection(global: *jsc.JSGlobalObject, root: JSValue, section_name: []const u8) bun.JSError!JSValue {
81	    var current = root;
82	    var part_iter = std.mem.splitScalar(u8, section_name, '.');
83	    while (part_iter.next()) |raw_part| {
84	        const part = std.mem.trim(u8, raw_part, " \t");
85	        if (part.len == 0) continue;
86	
87	        var key_str = bun.String.fromUTF8(part);
88	        defer key_str.deref();
89	
90	        const existing = current.getWithString(global, key_str);
91	        if (existing != .zero and existing != .js_undefined and existing.isObject() and !existing.isString()) {
92	            current = existing;
93	        } else {
94	            const new_obj = JSValue.createEmptyObject(global, 0);
95	            try current.putMayBeIndex(global, &key_str, new_obj);
96	            current = new_obj;
97	        }
98	    }
99	    return current;
100	}
101	
102	fn parseKeyValue(global: *jsc.JSGlobalObject, section: JSValue, line: []const u8) bun.JSError!void {
103	    const eq_idx = std.mem.indexOfScalar(u8, line, '=');
104	
105	    const key_raw = if (eq_idx) |idx| line[0..idx] else line;
106	    const key = std.mem.trim(u8, key_raw, " \t");
