pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callFrame.argument(0);

    if (input_value.isEmptyOrUndefinedOrNull()) {
        return global.throwInvalidArguments("Expected a string to parse", .{});
    }

    var input_slice = try input_value.toSlice(global, bun.default_allocator);
    defer input_slice.deinit();
    const src = input_slice.slice();

    const root = JSValue.createEmptyObject(global, 0);
    var current_section = root;

    var iter = std.mem.splitScalar(u8, src, '\n');
    while (iter.next()) |raw_line| {
        // Strip trailing \r for Windows line endings
        const line = trimLine(raw_line);
        const trimmed = std.mem.trim(u8, line, " \t");

        if (trimmed.len == 0) continue;
        // Comment lines
        if (trimmed[0] == ';' or trimmed[0] == '#') continue;

        // Section header: [section] or [section.subsection]
        if (trimmed[0] == '[') {
            const close = std.mem.indexOfScalar(u8, trimmed, ']') orelse continue;
            // Verify rest of line after ] is whitespace or comment
            if (close + 1 < trimmed.len) {
                var rest_is_ok = true;
                for (trimmed[close + 1 ..]) |c| {
                    switch (c) {
                        ' ', '\t' => {},
                        ';', '#' => break,
                        else => {
                            rest_is_ok = false;
                            break;
                        },
                    }
                }
                if (!rest_is_ok) {
                    // Treat as key=value if bracket line is malformed
                    try parseKeyValue(global, current_section, trimmed);
                    continue;
                }
            }
            const section_name = std.mem.trim(u8, trimmed[1..close], " \t");
            if (section_name.len == 0) continue;

            // Handle dotted section names: [a.b.c] -> root.a.b.c
            current_section = try getOrCreateSection(global, root, section_name);
            continue;
        }

        // Key = value (or just key)
        try parseKeyValue(global, current_section, trimmed);
    }

    return root;
}

fn getOrCreateSection(global: *jsc.JSGlobalObject, root: JSValue, section_name: []const u8) bun.JSError!JSValue {
    var current = root;
    var part_iter = std.mem.splitScalar(u8, section_name, '.');
    while (part_iter.next()) |raw_part| {
        const part = std.mem.trim(u8, raw_part, " \t");
        if (part.len == 0) continue;

        const existing = try current.get(global, part);
        if (existing) |val| {
            if (val.isObject() and !val.isString() and !val.isNull()) {
                current = val;
                continue;
            }
        }
        // Create new sub-object
        const new_obj = JSValue.createEmptyObject(global, 0);
        var key_str = bun.String.borrowUTF8(part);
        defer key_str.deref();
        try current.putMayBeIndex(global, &key_str, new_obj);
        current = new_obj;
    }
    return current;
}

fn parseKeyValue(global: *jsc.JSGlobalObject, section: JSValue, line: []const u8) bun.JSError!void {
    const eq_idx = std.mem.indexOfScalar(u8, line, '=');

    const key_raw = if (eq_idx) |idx| line[0..idx] else line;
    const key = std.mem.trim(u8, key_raw, " \t");
    if (key.len == 0) return;

    const value: JSValue = if (eq_idx) |idx| blk: {
        const val_raw = if (idx + 1 < line.len) line[idx + 1 ..] else "";
        break :blk coerceValue(global, std.mem.trim(u8, val_raw, " \t"));
    } else JSValue.jsBoolean(true);

    var key_str = bun.String.borrowUTF8(key);
    defer key_str.deref();
    try section.putMayBeIndex(global, &key_str, value);
}

fn stripCommentFromValue(val: []const u8) []const u8 {
    // Find unquoted ; or # that indicates an inline comment
    var in_double_quote = false;
    var in_single_quote = false;
    for (val, 0..) |c, i| {
        if (c == '"' and !in_single_quote) {
            in_double_quote = !in_double_quote;
        } else if (c == '\'' and !in_double_quote) {
            in_single_quote = !in_single_quote;
        } else if ((c == ';' or c == '#') and !in_double_quote and !in_single_quote) {
            return std.mem.trimRight(u8, val[0..i], " \t");
        }
    }
    return val;
}

fn coerceValue(global: *jsc.JSGlobalObject, raw: []const u8) JSValue {
    const val = stripCommentFromValue(raw);

    if (val.len == 0) {
        return ZigString.init("").toJS(global);
    }

    // Strip quotes
    if (val.len >= 2) {
        if ((val[0] == '"' and val[val.len - 1] == '"') or
            (val[0] == '\'' and val[val.len - 1] == '\''))
        {
            const inner = val[1 .. val.len - 1];
            return ZigString.fromUTF8(inner).toJS(global);
        }
    }

    // Boolean coercion
    if (bun.strings.eqlComptime(val, "true")) return JSValue.jsBoolean(true);
    if (bun.strings.eqlComptime(val, "false")) return JSValue.jsBoolean(false);

    // Null coercion
    if (bun.strings.eqlComptime(val, "null")) return .null;

    // Number coercion
    if (val.len > 0 and (val[0] == '-' or val[0] == '+' or (val[0] >= '0' and val[0] <= '9'))) {
        if (std.fmt.parseFloat(f64, val)) |num| {
            return JSValue.jsNumber(num);
        } else |_| {}
    }

    return ZigString.fromUTF8(val).toJS(global);
}

fn trimLine(line: []const u8) []const u8 {
    if (line.len > 0 and line[line.len - 1] == '\r') {
        return line[0 .. line.len - 1];
    }
    return line;
}

// --- Stringify ---

pub fn stringify(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callFrame.argument(0);

    if (value.isEmptyOrUndefinedOrNull()) {
        return global.throwInvalidArguments("Expected an object to stringify", .{});
    }

    if (!value.isObject() or value.isString()) {
        return global.throwInvalidArguments("Expected an object to stringify", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    // Pass 1: emit root-level primitive key=value pairs
    {
        var prop_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer prop_iter.deinit();

        while (try prop_iter.next()) |prop_name| {
            const prop_val = prop_iter.value;
            if (prop_val.isUndefined() or prop_val.isFunction() or prop_val.isSymbol()) continue;
            // Skip objects (handled in pass 2), but not null and not string
            if (prop_val.isObject() and !prop_val.isNull() and !prop_val.isString()) continue;

            try appendKeyValue(global, &builder, prop_name, prop_val);
        }
    }

    // Pass 2: emit sections for object-valued properties
    {
        var prop_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer prop_iter.deinit();

        while (try prop_iter.next()) |prop_name| {
            const prop_val = prop_iter.value;
            if (prop_val.isUndefined() or prop_val.isFunction() or prop_val.isSymbol()) continue;
            if (prop_val.isNull()) continue;
            if (!prop_val.isObject() or prop_val.isString()) continue;

            // It's an object -- emit as [section]
            try stringifySection(global, &builder, prop_name, prop_val, "");
        }
    }

    return builder.toString(global);
}

fn stringifySection(
    global: *jsc.JSGlobalObject,
    builder: *wtf.StringBuilder,
    section_name: bun.String,
    section_val: JSValue,
    prefix: []const u8,
) (bun.JSError || error{OutOfMemory})!void {
    // Build full section path
    if (prefix.len > 0) {
        builder.append(.latin1, "\n[");
        builder.append(.latin1, prefix);
        builder.append(.lchar, '.');
        builder.append(.string, section_name);
        builder.append(.latin1, "]\n");
    } else {
        builder.append(.latin1, "\n[");
        builder.append(.string, section_name);
        builder.append(.latin1, "]\n");
    }

    // Build the full prefix for sub-sections
    const new_prefix: []const u8 = new_prefix: {
        const sec_len = section_name.length();
        if (prefix.len > 0) {
            // prefix + "." + section_name
            const buf = try bun.default_allocator.alloc(u8, prefix.len + 1 + sec_len);
            @memcpy(buf[0..prefix.len], prefix);
            buf[prefix.len] = '.';
            for (0..sec_len) |i| {
                buf[prefix.len + 1 + i] = @intCast(section_name.charAt(i));
            }
            break :new_prefix buf;
        } else {
            const buf = try bun.default_allocator.alloc(u8, sec_len);
            for (0..sec_len) |i| {
                buf[i] = @intCast(section_name.charAt(i));
            }
            break :new_prefix buf;
        }
    };
    defer bun.default_allocator.free(new_prefix);

    // Emit primitive properties first
    {
        var prop_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try section_val.toObject(global),
        );
        defer prop_iter.deinit();

        while (try prop_iter.next()) |prop_name| {
            const prop_val = prop_iter.value;
            if (prop_val.isUndefined() or prop_val.isFunction() or prop_val.isSymbol()) continue;
            if (prop_val.isObject() and !prop_val.isNull() and !prop_val.isString()) continue;

            try appendKeyValue(global, builder, prop_name, prop_val);
        }
    }

    // Then recurse into sub-objects
    {
        var prop_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try section_val.toObject(global),
        );
        defer prop_iter.deinit();

        while (try prop_iter.next()) |prop_name| {
            const prop_val = prop_iter.value;
            if (prop_val.isUndefined() or prop_val.isFunction() or prop_val.isSymbol()) continue;
            if (prop_val.isNull()) continue;
            if (!prop_val.isObject() or prop_val.isString()) continue;

            try stringifySection(global, builder, prop_name, prop_val, new_prefix);
        }
    }
}

fn appendKeyValue(
    global: *jsc.JSGlobalObject,
    builder: *wtf.StringBuilder,
    key: bun.String,
    value: JSValue,
) bun.JSError!void {
    builder.append(.string, key);
    builder.append(.lchar, '=');

    if (value.isNull()) {
        builder.append(.latin1, "null");
    } else if (value.isBoolean()) {
        builder.append(.latin1, if (value.asBoolean()) "true" else "false");
    } else if (value.isNumber()) {
        if (value.isInt32()) {
            builder.append(.int, value.asInt32());
        } else {
            builder.append(.double, value.asNumber());
        }
    } else if (value.isString()) {
        const str = try value.toBunString(global);
        defer str.deref();
        builder.append(.string, str);
    } else {
        builder.append(.latin1, "");
    }

    builder.append(.lchar, '\n');
}

